import React, { useState } from 'react';
import JobList from '../../components/jobs/JobList';

const JobListContainer = ({ variant = 'simple', limit }) => {
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo', salary: '8jt', desc: 'Membangun arsitektur web modern menggunakan React & Laravel.' },
        { id: 2, title: 'React Engineer', company: 'TechEase', location: 'Jakarta', salary: '12jt', desc: 'Pengembangan UI interaktif dan performan.' },
        { id: 3, title: 'Marketing', company: 'Solopos', location: 'Solo', salary: '6jt', desc: 'Strategi konten digital dan pertumbuhan brand.' }
    ]);

    const displayJobs = limit ? jobs.slice(0, limit) : jobs;

    return (
        <div>
            <JobList 
                jobs={displayJobs} 
                variant={variant} 
            />
        </div>
    );
};

export default JobListContainer;
